// ── Folder card ─────────────────────────────────────────────────────────────

interface FolderCardProps {
  section: VfsSection
  isSelected: boolean
  onToggle: (path: string) => void
}

function FolderCard({ section, isSelected, onToggle }: FolderCardProps) {
  const visibleTypes = section.types.slice(0, 4)
  const overflow = section.types.length > 4 ? section.types.length - 4 : 0
  const count = section.items.length

  return (
    <button
      onClick={() => onToggle(section.path)}
      className={cn(
        'group relative flex flex-col rounded-2xl bg-card p-3.5 text-left shadow-sm',
        'transition-all hover:shadow-md focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring',
        isSelected && 'ring-2 ring-violet-500/70 shadow-md',
      )}
    >
      {/* Folder illustration */}
      <div className="relative mb-3 h-[72px]">
        {/* Tab */}
        <div className="absolute left-2 top-0 h-3 w-[38%] rounded-t-md bg-violet-400/40" />
        {/* Depth / shadow layer */}
        <div className="absolute inset-x-1 bottom-0 top-3 translate-y-1 scale-[0.97] rounded-xl bg-violet-400/25 blur-[3px]" />
        {/* Main body */}
        <div className="absolute inset-x-0 bottom-0 top-3 overflow-hidden rounded-xl bg-gradient-to-br from-violet-400 to-violet-600">
          {/* Source badges */}
          <div className="absolute bottom-2.5 left-2.5 flex -space-x-1.5">
            {visibleTypes.map((type) => (
              <SourceBadge key={type} type={type} />
            ))}
            {overflow > 0 && (
              <span className="flex h-6 w-6 items-center justify-center rounded-full bg-white/90 text-[9px] font-bold text-gray-700 ring-2 ring-white">
                +{overflow}
              </span>
            )}
          </div>
        </div>
      </div>

      <p className="text-sm font-semibold text-foreground leading-tight">{section.label}</p>
      <p className="mt-0.5 text-xs text-muted-foreground">
        {count === 0 ? 'No entities yet' : `Used by ${count} ${count === 1 ? 'entity' : 'entities'}`}
      </p>
    </button>
  )
}

// ── Main component ───────────────────────────────────────────────────────────

interface Props {
  selectedEntityId: string | null
}

export default function VfsTree({ selectedEntityId }: Props) {
  const navigate = useNavigate()
  const queryClient = useQueryClient()
  const { expandedPaths, togglePath } = useUiStore()
  const treeQuery = useQuery({
    queryKey: ['browse', 'tree'],
    queryFn: fetchBrowseTree,
    staleTime: 5 * 60_000,
    gcTime: 30 * 60_000,
    refetchOnWindowFocus: false,
    refetchOnReconnect: false,
    refetchOnMount: false,
  })
  const sections = treeQuery.data?.sections ?? []
  const loading = treeQuery.isPending
  const totalEntities = treeQuery.data?.totalEntities ?? 0
  const hasAnyEntities = totalEntities > 0

  useEffect(() => {
    const key = 'browse_refresh_last_run'
    const minIntervalMs = 60_000
    const lastRun = Number(window.sessionStorage.getItem(key) ?? '0')
    if (Date.now() - lastRun < minIntervalMs) return
    window.sessionStorage.setItem(key, String(Date.now()))

    void (async () => {
      const refreshed = await triggerBrowseRefresh()
      if (refreshed) {
        await queryClient.invalidateQueries({ queryKey: ['browse', 'tree'] })
      }
    })()
  }, [queryClient])

  return (
    <div className="flex h-full flex-col bg-gradient-to-b from-background to-muted/20">
      {/* Header */}
      <div className="sticky top-0 z-10 border-b bg-background/95 px-4 py-3 backdrop-blur supports-[backdrop-filter]:bg-background/80">
        <p className="text-xs font-semibold uppercase tracking-[0.14em] text-muted-foreground">
          Context Base
        </p>
        <div className="mt-2 flex items-end justify-between gap-2">
          <p className="text-sm font-medium text-foreground">Knowledge explorer</p>
          <span className="rounded-full border px-2 py-0.5 text-xs text-muted-foreground">
            {loading ? '...' : `${totalEntities} entities`}
          </span>
        </div>
        <p className="mt-1 text-xs text-muted-foreground">
          Browse by domain and drill into entities.
        </p>
      </div>

      {loading && (
        <div className="flex items-center gap-2 px-4 py-5 text-sm text-muted-foreground">
          <Loader2 className="size-4 animate-spin" />
          Loading entities...
        </div>
      )}

      {!loading && !hasAnyEntities && (
        <div className="m-4 rounded-xl border border-dashed bg-background/70 p-6 text-center text-sm text-muted-foreground">
          No entities found. Ingest some data first.
        </div>
      )}

      <div className="flex-1 overflow-y-auto">
        {/* Folder grid */}
        <div className="grid grid-cols-2 gap-2.5 p-3">
          {sections.map((section) => (
            <FolderCard
              key={section.path}
              section={section}
              isSelected={expandedPaths.has(section.path)}
              onToggle={togglePath}
            />
          ))}
        </div>

        {/* Expanded item lists */}
        {sections
          .filter((s) => expandedPaths.has(s.path))
          .map((section) => (
            <div key={`${section.path}-items`} className="px-3 pb-3">
              <p className="mb-1.5 px-0.5 text-xs font-medium text-muted-foreground">
                {section.label}
              </p>
              <ul className="overflow-hidden rounded-xl border bg-background/90 shadow-sm">
                {section.items.length === 0 && (
                  <li className="px-4 py-3 text-sm text-muted-foreground">
                    No entities in this section.
                  </li>
                )}
                {section.items.map((item) => {
                  const isActive = selectedEntityId === item.entityId
                  return (
                    <li key={item.entityId}>
                      <button
                        onClick={() => navigate(`/browse/${encodeURIComponent(item.entityId)}`)}
                        className={cn(
                          'flex w-full items-center gap-2 py-2 pl-4 pr-3 text-left text-sm transition-colors hover:bg-muted/60',
                          isActive && 'bg-muted font-medium text-foreground',
                        )}
                      >
                        <item.Icon className="size-3.5 shrink-0 text-muted-foreground" />
                        <span className="truncate">{item.label}</span>
                      </button>
                    </li>
                  )
                })}
              </ul>
            </div>
          ))}
      </div>

      <div className="px-4 py-3 text-xs text-muted-foreground">
        {hasAnyEntities
          ? 'Tip: Select a folder to view entities.'
          : 'Ingest data to populate this navigation tree.'}
      </div>
    </div>
  )
}

