import { Outlet } from 'react-router-dom'
import TopNav from './TopNav'

export default function AppShell() {
  return (
    <div className="flex h-screen flex-col overflow-hidden bg-background">
      <TopNav />
      <main className="flex-1 overflow-hidden">
        <Outlet />
      </main>
    </div>
  )
}

import { NavLink } from 'react-router-dom'
import { Database } from 'lucide-react'
import { Button } from '@/components/ui/button'

const MODES = [
  { to: '/browse', label: 'Browse' },
  { to: '/search', label: 'Search' },
  { to: '/review', label: 'Review' },
  { to: '/workflow', label: 'Graph' },
] as const

export default function TopNav() {
  return (
    <header className="flex h-12 shrink-0 items-center gap-6 border-b bg-card px-4">
      <div className="flex items-center gap-2">
        <Database className="size-4 text-primary" />
        <span className="text-sm font-semibold tracking-tight">Qontext</span>
      </div>

      <nav className="flex items-center gap-1">
        {MODES.map(({ to, label }) => (
          <NavLink key={to} to={to}>
            {({ isActive }) => (
              <Button variant={isActive ? 'secondary' : 'ghost'} size="sm">
                {label}
              </Button>
            )}
          </NavLink>
        ))}
      </nav>

      <div className="ml-auto flex items-center gap-2">
        <span className="text-xs text-muted-foreground">Context Layer</span>
      </div>
    </header>
  )
}

import type { ReactNode } from 'react'

interface Props {
  left: ReactNode
  center: ReactNode
  right: ReactNode
  leftWidthClass?: string
  rightWidthClass?: string
}

export default function ThreeColumnLayout({
  left,
  center,
  right,
  leftWidthClass = '280px',
  rightWidthClass = '320px',
}: Props) {
  return (
    <div
      className="grid h-full divide-x overflow-hidden"
      style={{ gridTemplateColumns: `${leftWidthClass} minmax(0, 1fr) ${rightWidthClass}` }}
    >
      <aside className="flex flex-col overflow-y-auto">{left}</aside>
      <section className="flex flex-col overflow-y-auto">{center}</section>
      <aside className="flex flex-col overflow-y-auto">{right}</aside>
    </div>
  )
}

import { Network } from 'lucide-react'
import { Card, CardContent, CardHeader } from '@/components/ui/card'
import { Separator } from '@/components/ui/separator'
import { Skeleton } from '@/components/ui/skeleton'
import { EntityTypeBadge } from '@/components/entity/EntityTypeBadge'
import { FactRow } from '@/components/entity/FactRow'
import { useEntity } from '@/hooks/useEntity'

interface Props {
  entityId: string | null
}

function LoadingSkeleton() {
  return (
    <div className="flex flex-col gap-4 p-4">
      <div className="flex items-center gap-2">
        <Skeleton className="h-5 w-16" />
        <Skeleton className="h-6 w-48" />
      </div>
      <Skeleton className="h-px w-full" />
      {[1, 2, 3, 4].map((i) => (
        <div key={i} className="flex items-center justify-between">
          <Skeleton className="h-4 w-32" />
          <Skeleton className="h-5 w-12" />
        </div>
      ))}
    </div>
  )
}

export default function EntityDetail({ entityId }: Props) {
  const { data, isLoading, isError } = useEntity(entityId)

  if (!entityId) {
    return (
      <div className="flex flex-1 flex-col items-center justify-center gap-3 p-8 text-center">
        <Network className="size-8 text-muted-foreground/40" />
        <p className="text-sm text-muted-foreground">
          Select an entity from the tree on the left to inspect its facts, provenance, and related
          entities.
        </p>
      </div>
    )
  }

  if (isLoading) return <LoadingSkeleton />

  if (isError || !data) {
    return (
      <div className="flex flex-col gap-4 p-4">
        <p className="text-sm text-muted-foreground">
          Backend not yet available. This panel will show full entity details once the API is live.
        </p>
        <Card>
          <CardContent className="pt-4">
            <p className="font-mono text-xs text-muted-foreground break-all">{entityId}</p>
          </CardContent>
        </Card>
      </div>
    )
  }

  const liveFacts = data.facts.filter((f) => f.status === 'live' || f.status === 'disputed')
  const disputedCount = data.facts.filter((f) => f.status === 'disputed').length

  return (
    <div className="flex flex-col gap-4 p-4">
      <Card>
        <CardHeader className="pb-3">
          <div className="flex items-start justify-between gap-2">
            <div className="flex flex-col gap-1.5">
              <EntityTypeBadge type={data.entity_type} />
              <h2 className="text-lg font-semibold leading-tight">{data.canonical_name}</h2>
              {data.aliases.length > 0 && (
                <p className="text-xs text-muted-foreground">
                  Also known as: {data.aliases.join(', ')}
                </p>
              )}
            </div>
            {disputedCount > 0 && (
              <span className="shrink-0 rounded-full bg-destructive/10 px-2 py-0.5 text-xs font-medium text-destructive">
                {disputedCount} conflict{disputedCount > 1 ? 's' : ''}
              </span>
            )}
          </div>
        </CardHeader>

        <CardContent className="flex flex-col gap-0">
          <p className="mb-2 text-xs font-semibold uppercase tracking-wider text-muted-foreground">
            Facts
          </p>
          {liveFacts.length === 0 ? (
            <p className="py-4 text-sm text-muted-foreground">
              This entity has no live facts yet.
            </p>
          ) : (
            liveFacts.map((fact, i) => (
              <div key={fact.id}>
                <FactRow fact={fact} />
                {i < liveFacts.length - 1 && <Separator />}
              </div>
            ))
          )}
        </CardContent>
      </Card>

      <p className="text-xs text-muted-foreground">
        Path: <span className="font-mono">{String(data.attrs?.vfs_path ?? `/entities/${data.id}`)}</span>
      </p>
    </div>
  )
}

