import { useEffect, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { useQuery, useQueryClient } from '@tanstack/react-query'
import { ChevronRight, FileText, Loader2 } from 'lucide-react'
import { cn } from '@/lib/utils'
import type { LucideIcon } from 'lucide-react'

// ── Data types ───────────────────────────────────────────────────────────────

interface VfsNode {
  entity_id: string
  path: string
  type: string
  content: { canonical_name?: string; [key: string]: unknown }
}

interface VfsListResponse {
  children: VfsNode[]
  total: number
}

interface VfsSection {
  path: string
  label: string
  types: string[]
  count?: number
  items: Array<{ entityId: string; label: string; Icon: LucideIcon; type: string }>
}

interface VfsSectionsResponse {
  sections: Array<{ path: string; label: string; types: string[]; count?: number }>
  total_sections: number
  total_entities: number
}

// ── Fetching ─────────────────────────────────────────────────────────────────

function pluralSegment(type: string): string {
  if (type.endsWith('y') && !/[aeiou]y$/.test(type)) return `${type.slice(0, -1)}ies`
  if (type.endsWith('s') || type.endsWith('x') || type.endsWith('z')) return `${type}es`
  return `${type}s`
}

async function fetchSections() {
  try {
    const res = await fetch('/api/vfs/_sections')
    if (!res.ok) return []
    const data: VfsSectionsResponse = await res.json()
    return data.sections ?? []
  } catch { return [] }
}

async function fetchType(type: string): Promise<VfsNode[]> {
  try {
    const res = await fetch(`/api/vfs/${pluralSegment(type)}`)
    if (!res.ok) return []
    const data: VfsListResponse = await res.json()
    return data.children ?? []
  } catch { return [] }
}

async function fetchBrowseTree() {
  const sectionDefs = await fetchSections()
  const allTypes = sectionDefs.flatMap((s) => s.types)
  const results = await Promise.all(
    allTypes.map((t) => fetchType(t).then((nodes) => ({ type: t, nodes }))),
  )
  const nodesByType = new Map(results.map((r) => [r.type, r.nodes]))
  const sections: VfsSection[] = sectionDefs.map((def) => ({
    ...def,
    items: def.types.flatMap((type) =>
      (nodesByType.get(type) ?? []).map((node) => ({
        entityId: node.entity_id,
        label: node.content?.canonical_name ?? node.entity_id,
        Icon: FileText,
        type,
      })),
    ),
  }))
  return { sections, totalEntities: sections.reduce((s, sec) => s + sec.items.length, 0) }
}

async function triggerBrowseRefresh() {
  try {
    const res = await fetch('/api/admin/refresh-browse-tree', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ limit: 250, infer_mappings: true, auto_approve_mappings: true, llm_extract: false }),
    })
    if (!res.ok) return false
    await res.json().catch(() => ({}))
    return true
  } catch { return false }
}

// ── Source badges ────────────────────────────────────────────────────────────

const TYPE_CONFIG: Record<string, { bg: string; label: string }> = {
  person:        { bg: 'bg-blue-500',    label: 'P'  },
  company:       { bg: 'bg-orange-500',  label: 'C'  },
  communication: { bg: 'bg-red-500',     label: 'M'  },
  email:         { bg: 'bg-red-500',     label: 'G'  },
  document:      { bg: 'bg-slate-700',   label: 'N'  },
  task:          { bg: 'bg-emerald-500', label: 'T'  },
  ticket:        { bg: 'bg-blue-600',    label: 'J'  },
  event:         { bg: 'bg-purple-500',  label: 'E'  },
  policy:        { bg: 'bg-pink-500',    label: 'Po' },
}

function SourceBadge({ type }: { type: string }) {
  const cfg = TYPE_CONFIG[type.toLowerCase()] ?? { bg: 'bg-slate-400', label: type.slice(0, 1).toUpperCase() }
  return (
    <span
      className={cn(
        'flex h-6 w-6 items-center justify-center rounded-full text-[9px] font-bold text-white ring-2 ring-white dark:ring-card',
        cfg.bg,
      )}
    >
      {cfg.label}
    </span>
  )
}

// ── Folder card ──────────────────────────────────────────────────────────────

function FolderCard({ section, onOpen }: { section: VfsSection; onOpen: (path: string) => void }) {
  const visibleTypes = section.types.slice(0, 4)
  const overflow = section.types.length > 4 ? section.types.length - 4 : 0
  const count = section.items.length

  return (
    <button
      onClick={() => onOpen(section.path)}
      className="group flex flex-col rounded-2xl bg-card p-4 text-left shadow-sm transition-all hover:shadow-lg hover:-translate-y-0.5 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
    >
      {/* Folder illustration */}
      <div className="relative mb-4 h-36 w-full">
        {/* Back layer */}
        <div className="absolute inset-x-3 top-1 bottom-4 translate-x-1 translate-y-1 rounded-2xl bg-violet-300/40 blur-[2px]" />
        {/* Tab */}
        <div className="absolute left-4 top-3 h-4 w-[38%] rounded-t-xl bg-violet-500/80" />
        {/* Front body */}
        <div className="absolute inset-x-0 top-7 bottom-0 overflow-hidden rounded-2xl bg-gradient-to-br from-violet-500 via-violet-600 to-violet-700">
          {/* Source badges */}
          <div className="absolute bottom-3 left-3 flex -space-x-1.5">
            {visibleTypes.map((type) => (
              <SourceBadge key={type} type={type} />
            ))}
            {overflow > 0 && (
              <span className="flex h-6 w-6 items-center justify-center rounded-full bg-white/90 text-[9px] font-bold text-gray-700 ring-2 ring-white">
                +{overflow}
              </span>
            )}
          </div>
        </div>
      </div>

      <p className="text-base font-semibold text-foreground">{section.label}</p>
      <p className="mt-0.5 text-sm text-muted-foreground">
        {count === 0 ? 'No entities yet' : `Used by ${count} ${count === 1 ? 'entity' : 'entities'}`}
      </p>
    </button>
  )
}

// ── File row (entity inside a folder) ───────────────────────────────────────

const TYPE_ICON_COLOR: Record<string, string> = {
  person: 'text-blue-500',
  company: 'text-orange-500',
  communication: 'text-red-500',
  document: 'text-slate-600',
  task: 'text-emerald-500',
  ticket: 'text-blue-600',
  event: 'text-purple-500',
  policy: 'text-pink-500',
}

function FileRow({
  item,
  isActive,
  onClick,
}: {
  item: VfsSection['items'][number]
  isActive: boolean
  onClick: () => void
}) {
  const colorClass = TYPE_ICON_COLOR[item.type.toLowerCase()] ?? 'text-muted-foreground'
  return (
    <button
      onClick={onClick}
      className={cn(
        'group flex w-full items-center gap-3 rounded-xl px-4 py-3 text-left transition-colors',
        isActive
          ? 'bg-accent text-accent-foreground'
          : 'hover:bg-muted/60',
      )}
    >
      <item.Icon className={cn('size-4 shrink-0', colorClass)} />
      <span className="flex-1 truncate text-sm font-medium text-foreground">{item.label}</span>
      <span className="shrink-0 rounded-full bg-muted px-2 py-0.5 text-xs capitalize text-muted-foreground">
        {item.type}
      </span>
      <ChevronRight className="size-4 shrink-0 text-muted-foreground opacity-0 transition-opacity group-hover:opacity-100" />
    </button>
  )
}

// ── Main component ───────────────────────────────────────────────────────────

interface Props {
  selectedEntityId: string | null
}

export default function VfsTree({ selectedEntityId }: Props) {
  const navigate = useNavigate()
  const queryClient = useQueryClient()
  const [openSection, setOpenSection] = useState<string | null>(null)

  const treeQuery = useQuery({
    queryKey: ['browse', 'tree'],
    queryFn: fetchBrowseTree,
    staleTime: 5 * 60_000,
    gcTime: 30 * 60_000,
    refetchOnWindowFocus: false,
    refetchOnReconnect: false,
    refetchOnMount: false,
  })

  const sections = treeQuery.data?.sections ?? []
  const loading = treeQuery.isPending
  const totalEntities = treeQuery.data?.totalEntities ?? 0
  const activeSection = sections.find((s) => s.path === openSection) ?? null

  // Auto-open the section that contains the active entity
  useEffect(() => {
    if (!selectedEntityId || openSection) return
    const sec = sections.find((s) => s.items.some((i) => i.entityId === selectedEntityId))
    if (sec) setOpenSection(sec.path)
  }, [selectedEntityId, sections, openSection])

  useEffect(() => {
    const key = 'browse_refresh_last_run'
    const minIntervalMs = 60_000
    const lastRun = Number(window.sessionStorage.getItem(key) ?? '0')
    if (Date.now() - lastRun < minIntervalMs) return
    window.sessionStorage.setItem(key, String(Date.now()))
    void (async () => {
      const refreshed = await triggerBrowseRefresh()
      if (refreshed) await queryClient.invalidateQueries({ queryKey: ['browse', 'tree'] })
    })()
  }, [queryClient])

  return (
    <div className="flex flex-col p-8 gap-6 min-h-full">
      {/* ── Header with breadcrumb ── */}
      <div className="flex items-center gap-2">
        {openSection ? (
          <>
            <button
              onClick={() => setOpenSection(null)}
              className="text-muted-foreground hover:text-foreground transition-colors text-2xl font-bold"
            >
              Context vaults
            </button>
            <ChevronRight className="size-5 text-muted-foreground" />
            <span className="text-2xl font-bold text-foreground">{activeSection?.label}</span>
          </>
        ) : (
          <h1 className="text-2xl font-bold text-foreground">Context vaults</h1>
        )}
        <span className="ml-auto rounded-full border px-2.5 py-0.5 text-xs text-muted-foreground">
          {loading ? '…' : `${totalEntities} entities`}
        </span>
      </div>

      {/* ── Loading ── */}
      {loading && (
        <div className="flex items-center gap-2 text-sm text-muted-foreground">
          <Loader2 className="size-4 animate-spin" />
          Loading…
        </div>
      )}

      {/* ── Empty state ── */}
      {!loading && totalEntities === 0 && (
        <div className="flex flex-1 items-center justify-center rounded-2xl border border-dashed p-12 text-center text-sm text-muted-foreground">
          No entities found. Ingest some data first.
        </div>
      )}

      {/* ── Folder grid (top level) ── */}
      {!loading && !openSection && sections.length > 0 && (
        <div className="grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-3">
          {sections.map((section) => (
            <FolderCard key={section.path} section={section} onOpen={setOpenSection} />
          ))}
        </div>
      )}

      {/* ── File list (inside a folder) ── */}
      {!loading && openSection && activeSection && (
        <div className="flex flex-col gap-1">
          {activeSection.items.length === 0 ? (
            <p className="py-8 text-center text-sm text-muted-foreground">
              This folder is empty.
            </p>
          ) : (
            activeSection.items.map((item) => (
              <FileRow
                key={item.entityId}
                item={item}
                isActive={selectedEntityId === item.entityId}
                onClick={() => navigate(`/browse/${encodeURIComponent(item.entityId)}`)}
              />
            ))
          )}
        </div>
      )}
    </div>
  )
}

