import { Outlet, NavLink } from 'react-router-dom'
import { Database } from 'lucide-react'

const NAV_ITEMS = [
  { to: '/browse',   label: 'Browse'  },
  { to: '/search',   label: 'Search'  },
  { to: '/review',   label: 'Review'  },
  { to: '/workflow', label: 'Graph'   },
] as const

export default function AppShell() {
  return (
    <div style={{ display: 'flex', height: '100vh', overflow: 'hidden', background: '#f5f5f7' }}>
      {/* ── Sidebar ── */}
      <aside style={{
        width: 196, flexShrink: 0, display: 'flex', flexDirection: 'column',
        borderRight: '1px solid #e5e5e5', background: '#fafafa', height: '100%',
      }}>
        {/* Logo */}
        <div style={{
          height: 52, display: 'flex', alignItems: 'center', gap: 9,
          padding: '0 15px', borderBottom: '1px solid #e5e5e5',
        }}>
          <div style={{
            width: 22, height: 22, borderRadius: 6, background: '#5b5bd6',
            display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0,
          }}>
            <Database size={11} color="white" strokeWidth={2.2} />
          </div>
          <span style={{ fontSize: 13, fontWeight: 600, letterSpacing: '-0.01em', color: '#0a0a0a' }}>
            Qontext
          </span>
        </div>

        {/* Nav */}
        <nav style={{ padding: '10px 8px', display: 'flex', flexDirection: 'column', gap: 1 }}>
          {NAV_ITEMS.map(({ to, label }) => (
            <NavLink key={to} to={to}>
              {({ isActive }) => (
                <div style={{
                  display: 'flex', alignItems: 'center', gap: 9,
                  padding: '6px 10px', borderRadius: 6, fontSize: 13,
                  background: isActive ? '#ebebeb' : 'transparent',
                  color: isActive ? '#0a0a0a' : '#999',
                  fontWeight: isActive ? 500 : 400,
                  cursor: 'pointer',
                  transition: 'background .12s',
                }}>
                  {label}
                </div>
              )}
            </NavLink>
          ))}
        </nav>

        <div style={{ marginTop: 'auto', padding: '12px 15px' }}>
          <span style={{ fontSize: 11, color: '#ccc' }}>Context Layer</span>
        </div>
      </aside>

      {/* ── Page content ── */}
      <main style={{ flex: 1, display: 'flex', overflow: 'hidden' }}>
        <Outlet />
      </main>
    </div>
  )
}

