import { useEffect, useMemo, useRef, useState } from 'react'
import { useParams, useNavigate } from 'react-router-dom'
import { searchMemory } from '@/lib/api'
import type { SearchResultItem } from '@/types'
import {
  cascadeFilter,
  describeResult,
  getConnectionCount,
  getTicketCount,
  parseInterpretation,
} from '../search/searchLogic'
import VfsTree from './VfsTree'
import EntityDetail from './EntityDetail'
import ActionPanel from './ActionPanel'

// ── Chat types (mirrors SearchPage) ─────────────────────────────────────────

interface AssistantPayload {
  text: string
  steps: string[]
  matches: SearchResultItem[]
}
interface ChatMessage {
  id: string
  role: 'user' | 'assistant'
  content: string
  payload?: AssistantPayload
}

function buildAssistantPayload(query: string, results: SearchResultItem[]): AssistantPayload {
  const intent = parseInterpretation(query)
  const { filtered, steps } = cascadeFilter(results, intent)
  if (filtered.length === 0) {
    return {
      text: 'Nichts Passendes gefunden. Versuche andere Suchbegriffe.',
      steps, matches: [],
    }
  }
  const top = filtered.slice(0, 6)
  return {
    text: `Top-Treffer:\n${top.map(r => `• ${describeResult(r.entity)}`).join('\n')}`,
    steps, matches: top,
  }
}

// ── Browse chat panel ────────────────────────────────────────────────────────

function BrowseChat() {
  const navigate = useNavigate()
  const [messages, setMessages] = useState<ChatMessage[]>([
    { id: 'init', role: 'assistant', content: 'Frag mich etwas — z. B. "Wo ist Anna Müller?" oder "Senior Engineers mit Tickets".' },
  ])
  const [input, setInput] = useState('')
  const [isLoading, setIsLoading] = useState(false)
  const [expanded, setExpanded] = useState(false)
  const endRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    if (expanded) endRef.current?.scrollIntoView({ behavior: 'smooth' })
  }, [messages, expanded])

  const canSend = useMemo(() => input.trim().length > 0 && !isLoading, [input, isLoading])

  async function handleSend() {
    const query = input.trim()
    if (!canSend || !query) return
    const intent = parseInterpretation(query)
    const needsWider = Boolean(
      intent.titleTerms.length > 0 || intent.ticketConstraint ||
      intent.connectionConstraint || intent.wantsConnections,
    )
    setMessages(prev => [...prev, { id: `u-${Date.now()}`, role: 'user', content: query }])
    setInput('')
    setIsLoading(true)
    setExpanded(true)
    try {
      const res = await searchMemory({ query, k: needsWider ? 120 : 40 })
      const payload = buildAssistantPayload(query, res.results)
      setMessages(prev => [...prev, { id: `a-${Date.now()}`, role: 'assistant', content: payload.text, payload }])
    } catch (err) {
      setMessages(prev => [...prev, { id: `e-${Date.now()}`, role: 'assistant', content: `Fehler: ${(err as Error).message}` }])
    } finally {
      setIsLoading(false)
    }
  }

  const extraMessages = messages.length - 1 // exclude init

  return (
    <div style={{ borderTop: '1px solid #e5e5e5', background: '#fff', flexShrink: 0 }}>
      {/* ── Message history (expandable) ── */}
      {expanded && (
        <div style={{ maxHeight: 220, overflowY: 'auto', padding: '10px 16px 4px' }}>
          {messages.map(msg => (
            <div
              key={msg.id}
              style={{ marginBottom: 8, display: 'flex', justifyContent: msg.role === 'user' ? 'flex-end' : 'flex-start' }}
            >
              <div style={{
                maxWidth: '88%',
                background: msg.role === 'user' ? '#0a0a0a' : '#f3f3f3',
                color: msg.role === 'user' ? '#fff' : '#0a0a0a',
                borderRadius: 12, padding: '7px 12px',
                fontSize: 13, whiteSpace: 'pre-wrap', lineHeight: 1.45,
              }}>
                {msg.content}

                {/* Entity result cards */}
                {msg.payload && msg.payload.matches.length > 0 && (
                  <div style={{ marginTop: 8, display: 'flex', flexDirection: 'column', gap: 4 }}>
                    {msg.payload.matches.map(match => (
                      <button
                        key={match.entity.id}
                        onClick={() => navigate(`/browse/${encodeURIComponent(match.entity.id)}`)}
                        style={{
                          background: '#fff', border: '1px solid #e5e5e5',
                          borderRadius: 8, padding: '6px 10px',
                          textAlign: 'left', cursor: 'pointer',
                          transition: 'background .12s',
                        }}
                        onMouseEnter={e => (e.currentTarget.style.background = '#f7f7f7')}
                        onMouseLeave={e => (e.currentTarget.style.background = '#fff')}
                      >
                        <p style={{ fontWeight: 600, color: '#0a0a0a', fontSize: 12.5, marginBottom: 1 }}>
                          {match.entity.canonical_name}
                        </p>
                        <p style={{ color: '#aaa', fontSize: 11 }}>
                          {String(match.entity.entity_type)}
                          {' · '}Score {(match.score * 100).toFixed(0)}
                          {' · '}{getConnectionCount(match.entity)} Connections
                          {' · '}{getTicketCount(match.entity)} Tickets
                        </p>
                      </button>
                    ))}
                  </div>
                )}
              </div>
            </div>
          ))}

          {isLoading && (
            <div style={{ marginBottom: 8, display: 'flex' }}>
              <div style={{ background: '#f3f3f3', borderRadius: 12, padding: '7px 12px', fontSize: 13, color: '#aaa' }}>
                <span style={{ animation: 'pulse 1.5s ease-in-out infinite' }}>Thinking…</span>
              </div>
            </div>
          )}
          <div ref={endRef} />
        </div>
      )}

      {/* ── Input bar ── */}
      <div style={{ padding: '10px 14px 12px' }}>
        <div style={{
          display: 'flex', alignItems: 'center', gap: 8,
          background: '#f7f7f7', border: '1px solid #e5e5e5',
          borderRadius: 22, padding: '7px 8px 7px 14px',
        }}>
          {/* Toggle history badge */}
          {extraMessages > 0 && (
            <button
              onClick={() => setExpanded(e => !e)}
              style={{
                background: expanded ? '#0a0a0a' : '#ebebeb',
                color: expanded ? '#fff' : '#888',
                border: 'none', borderRadius: 10, padding: '2px 8px',
                fontSize: 11, fontWeight: 600, cursor: 'pointer', flexShrink: 0,
              }}
            >
              {expanded ? '▾' : '▴'} {extraMessages}
            </button>
          )}
          <input
            value={input}
            onChange={e => setInput(e.target.value)}
            onKeyDown={e => { if (e.key === 'Enter') { e.preventDefault(); void handleSend() } }}
            placeholder='z. B. "Wo ist Anna Müller?" oder "Senior Engineers mit Tickets"'
            style={{
              flex: 1, background: 'transparent', border: 'none', outline: 'none',
              fontSize: 13, color: '#0a0a0a',
            }}
          />
          <button
            onClick={() => void handleSend()}
            disabled={!canSend}
            style={{
              width: 30, height: 30, borderRadius: '50%', border: 'none',
              background: canSend ? '#0a0a0a' : '#e8e8e8',
              cursor: canSend ? 'pointer' : 'default', flexShrink: 0,
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              transition: 'background .15s',
            }}
          >
            <svg width="13" height="13" viewBox="0 0 24 24" fill="none"
              stroke={canSend ? '#fff' : '#bbb'} strokeWidth="2.5"
              strokeLinecap="round" strokeLinejoin="round">
              <line x1="22" y1="2" x2="11" y2="13"/>
              <polygon points="22 2 15 22 11 13 2 9 22 2"/>
            </svg>
          </button>
        </div>
      </div>
    </div>
  )
}

// ── Page ─────────────────────────────────────────────────────────────────────

export default function BrowsePage() {
  const { entityId } = useParams<{ entityId: string }>()
  const navigate = useNavigate()
  const activeId = entityId ? decodeURIComponent(entityId) : null

  return (
    <div style={{ display: 'flex', height: '100%', width: '100%', overflow: 'hidden' }}>

      {/* ── Center: folder/file browser + chat ── */}
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        <VfsTree selectedEntityId={activeId} />
        <BrowseChat />
      </div>

      {/* ── Right: info panel – always visible ── */}
      <aside style={{
        width: 280, flexShrink: 0,
        borderLeft: '1px solid #e5e5e5', background: '#fff',
        display: 'flex', flexDirection: 'column', overflow: 'hidden',
      }}>
        <div style={{
          height: 52, flexShrink: 0, display: 'flex', alignItems: 'center',
          justifyContent: 'space-between', padding: '0 16px',
          borderBottom: '1px solid #e5e5e5',
        }}>
          <span style={{ fontSize: 11, fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.06em', color: '#ccc' }}>
            Info
          </span>
          {activeId && (
            <button
              onClick={() => navigate('/browse')}
              style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#ccc', padding: 3, borderRadius: 5 }}
            >
              <svg width="13" height="13" viewBox="0 0 13 13" fill="none">
                <path d="M1.5 1.5l10 10M11.5 1.5l-10 10" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
              </svg>
            </button>
          )}
        </div>

        <div style={{ flex: 1, overflowY: 'auto' }}>
          {!activeId ? (
            <div style={{
              display: 'flex', flexDirection: 'column', alignItems: 'center',
              justifyContent: 'center', gap: 10, padding: 28, textAlign: 'center', height: '100%',
            }}>
              <svg width="34" height="34" viewBox="0 0 34 34" fill="none" style={{ opacity: 0.15 }}>
                <circle cx="17" cy="17" r="16" stroke="#0a0a0a" strokeWidth="1.5"/>
                <path d="M17 11v8M17 22v2" stroke="#0a0a0a" strokeWidth="1.8" strokeLinecap="round"/>
              </svg>
              <p style={{ fontSize: 12.5, color: '#ccc', lineHeight: 1.6 }}>
                Datei auswählen<br/>um Details zu sehen
              </p>
            </div>
          ) : (
            <>
              <EntityDetail entityId={activeId} />
              <ActionPanel entityId={activeId} />
            </>
          )}
        </div>
      </aside>
    </div>
  )
}

